# Generated by openai (gpt-5.4-mini)
# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from fastapi import FastAPI, HTTPException
from pydantic import BaseModel, Field
from typing import Dict, List, Optional, Any
from collections import defaultdict, Counter
from threading import Lock
import uuid
import numpy as np
import torch
import torch.nn as nn
import torch.optim as optim
from torchvision import models, transforms
from PIL import Image
import io
import base64

app = FastAPI(title="Crowdsourced Data Labeling System")

lock = Lock()

images: Dict[str, Dict[str, Any]] = {}
annotations: Dict[str, List[Dict[str, Any]]] = defaultdict(list)
aggregated_labels: Dict[str, Any] = {}
label_to_idx: Dict[str, int] = {}
idx_to_label: Dict[int, str] = {}
trained_model = None


class ImageCreateRequest(BaseModel):
    image_base64: str = Field(..., description="Base64-encoded image data")
    metadata: Optional[Dict[str, Any]] = None


class ImageCreateResponse(BaseModel):
    image_id: str


class AnnotationRequest(BaseModel):
    image_id: str
    annotator_id: str
    label: str
    confidence: Optional[float] = None


class AnnotationResponse(BaseModel):
    status: str


class AggregateResponse(BaseModel):
    image_id: str
    aggregated_label: Optional[str]
    label_counts: Dict[str, int]


class TrainRequest(BaseModel):
    epochs: int = 1
    batch_size: int = 8
    lr: float = 1e-3
    image_size: int = 224


class TrainResponse(BaseModel):
    status: str
    num_samples: int
    num_classes: int


def decode_image(image_base64: str) -> Image.Image:
    try:
        raw = base64.b64decode(image_base64)
        return Image.open(io.BytesIO(raw)).convert("RGB")
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Invalid image data: {e}")


def get_or_create_label_index(label: str) -> int:
    if label not in label_to_idx:
        idx = len(label_to_idx)
        label_to_idx[label] = idx
        idx_to_label[idx] = label
    return label_to_idx[label]


def majority_vote(image_id: str) -> Optional[str]:
    anns = annotations.get(image_id, [])
    if not anns:
        return None
    counts = Counter(a["label"] for a in anns)
    top = counts.most_common()
    if not top:
        return None
    max_count = top[0][1]
    winners = [label for label, count in top if count == max_count]
    return sorted(winners)[0]


class LabeledImageDataset(torch.utils.data.Dataset):
    def __init__(self, items, image_size=224):
        self.items = items
        self.transform = transforms.Compose([
            transforms.Resize((image_size, image_size)),
            transforms.ToTensor(),
            transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
        ])

    def __len__(self):
        return len(self.items)

    def __getitem__(self, idx):
        image_id, label = self.items[idx]
        img = decode_image(images[image_id]["image_base64"])
        x = self.transform(img)
        y = label_to_idx[label]
        return x, y


def build_model(num_classes: int):
    model = models.resnet18(weights=None)
    model.fc = nn.Linear(model.fc.in_features, num_classes)
    return model


@app.post("/images", response_model=ImageCreateResponse)
def create_image(req: ImageCreateRequest):
    image_id = str(uuid.uuid4())
    with lock:
        images[image_id] = {
            "image_base64": req.image_base64,
            "metadata": req.metadata or {},
        }
    return ImageCreateResponse(image_id=image_id)


@app.post("/annotations", response_model=AnnotationResponse)
def submit_annotation(req: AnnotationRequest):
    with lock:
        if req.image_id not in images:
            raise HTTPException(status_code=404, detail="Image not found")
        annotations[req.image_id].append({
            "annotator_id": req.annotator_id,
            "label": req.label,
            "confidence": req.confidence,
        })
        get_or_create_label_index(req.label)
    return AnnotationResponse(status="ok")


@app.get("/aggregate/{image_id}", response_model=AggregateResponse)
def aggregate(image_id: str):
    with lock:
        if image_id not in images:
            raise HTTPException(status_code=404, detail="Image not found")
        anns = annotations.get(image_id, [])
        counts = Counter(a["label"] for a in anns)
        label_counts = dict(counts)
        agg = majority_vote(image_id)
        aggregated_labels[image_id] = agg
    return AggregateResponse(image_id=image_id, aggregated_label=agg, label_counts=label_counts)


@app.post("/train", response_model=TrainResponse)
def train(req: TrainRequest):
    global trained_model
    with lock:
        labeled_items = []
        for image_id in images:
            label = aggregated_labels.get(image_id)
            if label is None:
                label = majority_vote(image_id)
                aggregated_labels[image_id] = label
            if label is not None:
                labeled_items.append((image_id, label))

        if not labeled_items:
            raise HTTPException(status_code=400, detail="No labeled data available for training")

        for _, label in labeled_items:
            get_or_create_label_index(label)

        dataset = LabeledImageDataset(labeled_items, image_size=req.image_size)
        loader = torch.utils.data.DataLoader(dataset, batch_size=req.batch_size, shuffle=True)

        num_classes = len(label_to_idx)
        model = build_model(num_classes)
        criterion = nn.CrossEntropyLoss()
        optimizer = optim.Adam(model.parameters(), lr=req.lr)

        model.train()
        for _ in range(req.epochs):
            for xb, yb in loader:
                optimizer.zero_grad()
                logits = model(xb)
                loss = criterion(logits, yb)
                loss.backward()
                optimizer.step()

        trained_model = model
    return TrainResponse(status="trained", num_samples=len(labeled_items), num_classes=num_classes)


@app.get("/labels/{image_id}")
def get_labels(image_id: str):
    with lock:
        if image_id not in images:
            raise HTTPException(status_code=404, detail="Image not found")
        return {
            "image_id": image_id,
            "annotations": annotations.get(image_id, []),
            "aggregated_label": aggregated_labels.get(image_id),
        }


@app.get("/health")
def health():
    return {"status": "ok"}